397	    #[test]
398	    fn mpsc_init_seeds_seq_array() {
399	        let mut r = Region::new();
400	        // Dirty the region so the seq stores are observable.
401	        r.0.fill(0xAA);
402	        let ring = MpscRing::init(&mut r.0, 64, 4).unwrap();
403	        for i in 0..4 {
404	            // SAFETY: i < capacity; test mirrors init's bounds.
405	            let seq = unsafe { &*ring.seqs.add(i as usize) };
406	            assert_eq!(seq.load(Ordering::Relaxed), i);
407	        }
408	        assert_eq!(ring.slot_size, 64);
409	        assert_eq!(ring.capacity, 4);
410	        assert_eq!(ring.mask, 3);
411	    }
412	
413	    #[test]
414	    fn mpsc_attach_validates_header() {
415	        let mut r = Region::new();
416	        // Not initialized yet: magic is zero.
417	        let err = unsafe { MpscRing::attach(r.0.as_mut_ptr(), r.0.len()) }
418	            .err()
419	            .unwrap();
420	        assert_eq!(err, Error::BadMagic);
421	        MpscRing::init(&mut r.0, 64, 4).unwrap();
422	        let ring = unsafe { MpscRing::attach(r.0.as_mut_ptr(), r.0.len()) }.unwrap();
423	        assert_eq!(ring.slot_size, 64);
424	        assert_eq!(ring.capacity, 4);
425	        // A different recorded cache line is rejected.
426	        ring.header.cache_line_size.store(128, Ordering::Relaxed);
427	        let err = unsafe { MpscRing::attach(r.0.as_mut_ptr(), r.0.len()) }
428	            .err()
429	            .unwrap();
430	        assert_eq!(err, Error::BadCacheLine);
431	    }
