451	    use crate::{Empty, Full};
452	    use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
453	
454	    /// Test message; two words so a torn write would be
455	    /// visible, `val` doubles as the producer id in threaded
456	    /// tests.
457	    #[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
458	    #[repr(C)]
459	    struct Msg {
460	        seq: u64,
461	        val: u64,
462	    }
463	
464	    #[test]
465	    fn mpsc_roundtrip_full_empty() {
466	        let mut r = Region::new();
467	        let (prod, mut cons) = MpscRing::init(&mut r.0, 64, 4).unwrap().split();
468	
469	        // Empty at start.
470	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
471	
472	        // Fill all 4 slots, then Full on a single probe.
473	        for i in 0..4u64 {
474	            prod.send_with::<Msg>(
475	                |_| false,
476	                |m| {
477	                    m.seq = i;
478	                    m.val = i * 10;
479	                },
480	            )
481	            .unwrap();
482	        }
483	        assert_eq!(
484	            prod.send_with::<Msg>(|_| false, |_| {}).err().unwrap(),
485	            Full
486	        );
487	
488	        // Drain in order; then empty again.
489	        for i in 0..4u64 {
490	            let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
491	            assert_eq!(
492	                *msg,
493	                Msg {
494	                    seq: i,
495	                    val: i * 10
496	                }
497	            );
498	            msg.release();
499	        }
500	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
501	
502	        // One more send lands in the masked-around slot 0.
503	        prod.send_with::<Msg>(
504	            |_| false,
505	            |m| {
506	                m.seq = 4;
507	                m.val = 0;
508	            },
509	        )
510	        .unwrap();
511	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
512	        assert_eq!(msg.seq, 4);
513	        msg.release();
514	    }
