516	    #[test]
517	    fn mpsc_policies_count_and_give_up() {
518	        let mut r = Region::new();
519	        let (prod, mut cons) = MpscRing::init(&mut r.0, 64, 4).unwrap().split();
520	
521	        // Empty ring: the consumer's policy sees 0-based
522	        // attempts and its `false` becomes Err(Empty).
523	        let mut seen = Vec::new();
524	        let err = cons
525	            .reserve_slot_with::<Msg>(|attempt| {
526	                seen.push(attempt);
527	                attempt < 2
528	            })
529	            .err()
530	            .unwrap();
531	        assert_eq!(err, Empty);
532	        assert_eq!(seen, [0, 1, 2]);
533	
534	        // Fill the ring: the producer's policy gives up with
535	        // Err(Full), and the failed send has zero footprint —
536	        // the fill closure never ran.
537	        for i in 0..4u64 {
538	            prod.send_with::<Msg>(|_| false, |m| m.seq = i).unwrap();
539	        }
540	        let mut seen = Vec::new();
541	        let err = prod
542	            .send_with::<Msg>(
543	                |attempt| {
544	                    seen.push(attempt);
545	                    attempt < 2
546	                },
547	                |_| panic!("fill ran on a full ring"),
548	            )
549	            .err()
550	            .unwrap();
551	        assert_eq!(err, Full);
552	        assert_eq!(seen, [0, 1, 2]);
553	
554	        // With room / messages available the policy is never
555	        // consulted.
556	        let msg = cons
557	            .reserve_slot_with::<Msg>(|_| panic!("policy consulted with a message available"))
558	            .unwrap();
559	        assert_eq!(msg.seq, 0);
560	        msg.release();
561	        prod.send_with::<Msg>(
562	            |_| panic!("policy consulted with room available"),
563	            |m| m.seq = 4,
564	        )
565	        .unwrap();
566	    }
