568	    #[test]
569	    // Dropping the guard is the behavior under test.
570	    #[allow(clippy::drop_non_drop)]
571	    fn mpsc_abandoned_read_guard_redelivers() {
572	        let mut r = Region::new();
573	        let (prod, mut cons) = MpscRing::init(&mut r.0, 64, 4).unwrap().split();
574	
575	        prod.send_with::<Msg>(|_| false, |m| m.seq = 1).unwrap();
576	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
577	        assert_eq!(msg.seq, 1);
578	        drop(msg);
579	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
580	        assert_eq!(msg.seq, 1);
581	        msg.release();
582	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
583	    }
