660	    #[test]
661	    fn threaded_mpsc_two_producers() {
662	        // Reduced under Miri: interpreted spin loops are slow.
663	        const COUNT: u64 = if cfg!(miri) { 100 } else { 50_000 };
664	        const PRODUCERS: u64 = 2;
665	        let mut r = Region::new();
666	        let (prod, mut cons) = MpscRing::init(&mut r.0, 64, 4).unwrap().split();
667	
668	        std::thread::scope(|s| {
669	            for p in 0..PRODUCERS {
670	                let prod = prod.clone();
671	                s.spawn(move || {
672	                    for i in 0..COUNT {
673	                        prod.send_with::<Msg>(crate::policy::spin, |m| {
674	                            m.seq = i;
675	                            m.val = p;
676	                        })
677	                        .unwrap(); // OK: policy::spin never gives up
678	                    }
679	                });
680	            }
681	            s.spawn(move || {
682	                // Global arrival order is claim order; only
683	                // per-producer FIFO is promised.
684	                let mut next = [0u64; PRODUCERS as usize];
685	                for _ in 0..PRODUCERS * COUNT {
686	                    let msg = cons.reserve_slot_with::<Msg>(crate::policy::spin).unwrap(); // OK: policy::spin never gives up
687	                    let p = msg.val as usize;
688	                    assert_eq!(msg.seq, next[p], "per-producer order broken");
689	                    next[p] += 1;
690	                    msg.release();
691	                }
692	                assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
693	            });
694	        });
695	    }
