46	/// Cache-line size the layout is built around.
47	///
48	/// - Slot size must be a multiple of this; slots and the region
49	///   itself must be aligned to it.
50	pub const CACHE_LINE_SIZE: usize = 64;
51	
52	/// Layout marker written by [`Ring::init`]; rejects foreign
53	/// regions on attach.
54	const MAGIC: u32 = 0x5A43_5231; // "ZCR1"
55	
56	/// Bumped on any change to the region layout.
57	const LAYOUT_VERSION: u32 = 2;
58	
59	/// Number of `AtomicU32` words in the header's app-owned
60	/// `user` line.
61	pub const USER_WORDS: usize = 16;
62	
63	/// Cache-line-aligned wrapper granting its field sole
64	/// ownership of the line.
65	///
66	/// - `repr(align(N))` accepts only an integer literal — it
67	///   cannot name [`CACHE_LINE_SIZE`] — so the `64` is written out
68	///   and a const assert ties them back together.
69	#[repr(C, align(64))]
70	struct CacheAligned<T>(T);
71	
72	const _: () = assert!(align_of::<CacheAligned<AtomicU32>>() == CACHE_LINE_SIZE);
73	
74	impl<T> core::ops::Deref for CacheAligned<T> {
75	    type Target = T;
76	    /// Access the wrapped value.
77	    fn deref(&self) -> &T {
78	        &self.0
79	    }
80	}
