82	/// Control block at offset 0 of the region — one struct spanning
83	/// four cache lines so each concurrently-written index owns its
84	/// own line.
85	///
86	/// - line 0: geometry, written by [`Ring::init`] with `magic`
87	///   last (`Release`), read-only thereafter. Cold: per-op
88	///   paths use the handles' snapshots.
89	/// - line 1: `producer_idx`, written only by the producer.
90	/// - line 2: `consumer_idx`, written only by the consumer.
91	/// - line 3: `user`, app-owned scratch — last, so an app
92	///   overrun walks into its own slot data, not an index line.
93	/// - Every field is atomic: the region may be mapped by a peer
94	///   at any time, so even "immutable" fields must be free of
95	///   data races. `AtomicU32` has the same layout as `u32`, so
96	///   this does not affect `layout_version`.
97	#[repr(C)]
98	pub struct Header {
99	    /// Layout marker ([`MAGIC`]); stored last by init
100	    /// (`Release`), loaded first by attach (`Acquire`), so a
101	    /// peer that observes it also observes the geometry.
102	    magic: AtomicU32,
103	    /// Layout version ([`LAYOUT_VERSION`]).
104	    layout_version: AtomicU32,
105	    /// Slot size N in bytes — a [`CACHE_LINE_SIZE`] multiple.
106	    slot_size: AtomicU32,
107	    /// Slot count M — a power of two `<= 2^31`.
108	    capacity: AtomicU32,
109	    /// [`CACHE_LINE_SIZE`] this region was built with. The line size
110	    /// is a layout parameter (padding, offsets, slot granule),
111	    /// so builds must agree; attach validates it like the rest
112	    /// of the geometry.
113	    cache_line_size: AtomicU32,
114	    /// Free-running count of messages committed.
115	    producer_idx: CacheAligned<AtomicU32>,
116	    /// Free-running count of messages released.
117	    consumer_idx: CacheAligned<AtomicU32>,
118	    /// App-owned scratch line ([`USER_WORDS`] words): zeroed by
119	    /// init, then never read, written, or interpreted by the
120	    /// crate. See the design doc's "Blocking and user words".
121	    user: CacheAligned<[AtomicU32; USER_WORDS]>,
122	}
123	
124	const _: () = assert!(size_of::<Header>() == 4 * CACHE_LINE_SIZE);
125	
126	/// Errors from region validation — [`Ring::init`] /
127	/// [`Ring::attach`] and [`Pool::init`] / [`Pool::attach`].
128	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
129	pub enum Error {
130	    /// Region is not [`CACHE_LINE_SIZE`]-aligned.
131	    Misaligned,
132	    /// Region is smaller than header + slots/buffers.
133	    TooSmall,
134	    /// Slot size is zero or not a [`CACHE_LINE_SIZE`] multiple.
135	    BadSlotSize,
136	    /// Capacity is zero, not a power of two, or `> 2^31`.
137	    BadCapacity,
138	    /// Pool: buffer size is zero or not a [`CACHE_LINE_SIZE`]
139	    /// multiple.
140	    BadBufSize,
141	    /// Pool: buffer count is zero or `u32::MAX` (the
142	    /// free-stack NIL sentinel).
143	    BadBufCount,
144	    /// Attach: magic mismatch — not a region of the expected
145	    /// kind.
146	    BadMagic,
147	    /// Attach: layout version mismatch.
148	    BadLayoutVersion,
149	    /// Attach: region built with a different [`CACHE_LINE_SIZE`].
150	    BadCacheLine,
151	}
152	
153	/// A validated view over a ring region; split into the two
154	/// endpoint handles with [`Ring::split`].
155	///
156	/// - Geometry is snapshotted out of the header at
157	///   init/attach: per-op paths never re-read fields a peer
158	///   could scribble on, so a hostile peer can degrade the ring
159	///   to garbage messages or spurious Full/Empty, never to UB.
160	pub struct Ring<'a> {
161	    /// The region's control block.
162	    header: &'a Header,
163	    /// Base of the slot array (offset `size_of::<Header>()`).
164	    slots: *mut u8,
165	    /// Snapshot of `header.slot_size`.
166	    slot_size: u32,
167	    /// Snapshot of `header.capacity`.
168	    capacity: u32,
169	    /// Slot-position mask (`capacity - 1`).
170	    mask: u32,
171	    _region: PhantomData<&'a [u8]>,
172	}
173	
174	impl<'a> Ring<'a> {
175	    /// Initialize a fresh region and return the ring over it.
176	    ///
177	    /// - `slot_size` — N bytes per slot, a [`CACHE_LINE_SIZE`]
178	    ///   multiple.
179	    /// - `capacity` — M slots, a power of two `<= 2^31`.
180	    /// - The region must be [`CACHE_LINE_SIZE`]-aligned and at least
181	    ///   `size_of::<Header>() + M * N` bytes.
182	    pub fn init(region: &'a mut [u8], slot_size: u32, capacity: u32) -> Result<Self, Error> {
183	        validate_geometry(slot_size, capacity)?;
184	        let len = region.len();
185	        // Taken exactly once: a second `as_mut_ptr()` would
186	        // retag the slice and invalidate `header` under Stacked
187	        // Borrows (Miri-verified).
188	        let base = region.as_mut_ptr();
189	        let header = header_ptr(base, len)?;
190	        if (len as u64) < region_size(slot_size, capacity) {
191	            return Err(Error::TooSmall);
192	        }
193	        // SAFETY: alignment + room for the Header checked by
194	        // header_ptr; region is exclusively borrowed for 'a;
195	        // any byte pattern is a valid Header (all-atomic
196	        // fields, plain-byte padding).
197	        let header = unsafe { &*header };
198	        header
199	            .layout_version
200	            .store(LAYOUT_VERSION, Ordering::Relaxed);
201	        header.slot_size.store(slot_size, Ordering::Relaxed);
202	        header.capacity.store(capacity, Ordering::Relaxed);
203	        header
204	            .cache_line_size
205	            .store(CACHE_LINE_SIZE as u32, Ordering::Relaxed);
206	        header.producer_idx.store(0, Ordering::Relaxed);
207	        header.consumer_idx.store(0, Ordering::Relaxed);
208	        for word in header.user.iter() {
209	            word.store(0, Ordering::Relaxed);
210	        }
211	        // Published last: a peer that pre-mapped the region must
212	        // never observe MAGIC before the geometry it validates.
213	        // (Re-initializing a region a peer is already attached
214	        // to is outside the contract.)
215	        header.magic.store(MAGIC, Ordering::Release);
216	        // SAFETY: in bounds — region.len() >= header + slots.
217	        let slots = unsafe { base.add(size_of::<Header>()) };
218	        Ok(Ring {
219	            header,
220	            slots,
221	            slot_size,
222	            capacity,
223	            mask: capacity - 1,
224	            _region: PhantomData,
225	        })
226	    }
227	
228	    /// Attach to a region another process (or an earlier call)
229	    /// already initialized, validating its header.
230	    ///
231	    /// # Safety
232	    ///
233	    /// - `region` points to `len` bytes of memory that outlive
234	    ///   `'a`, genuinely shared and writable (e.g. a
235	    ///   `MAP_SHARED` mapping).
236	    /// - No other producer attaches if this side will produce;
237	    ///   likewise for the consumer side (SPSC contract).
238	    pub unsafe fn attach(region: *mut u8, len: usize) -> Result<Self, Error> {
239	        let header = header_ptr(region, len)?;
240	        // SAFETY: alignment + room for the Header checked by
241	        // header_ptr; caller guarantees the memory is live and
242	        // shared.
243	        let header = unsafe { &*header };
244	        // Acquire pairs with init's Release store of magic: a
245	        // valid magic means the geometry stores are visible.
246	        if header.magic.load(Ordering::Acquire) != MAGIC {
247	            return Err(Error::BadMagic);
248	        }
249	        if header.layout_version.load(Ordering::Relaxed) != LAYOUT_VERSION {
250	            return Err(Error::BadLayoutVersion);
251	        }
252	        if header.cache_line_size.load(Ordering::Relaxed) != CACHE_LINE_SIZE as u32 {
253	            return Err(Error::BadCacheLine);
254	        }
255	        // Snapshot geometry once; per-op paths never re-read it.
256	        let slot_size = header.slot_size.load(Ordering::Relaxed);
257	        let capacity = header.capacity.load(Ordering::Relaxed);
258	        validate_geometry(slot_size, capacity)?;
259	        if (len as u64) < region_size(slot_size, capacity) {
260	            return Err(Error::TooSmall);
261	        }
262	        // SAFETY: in bounds — len >= header + slots.
263	        let slots = unsafe { region.add(size_of::<Header>()) };
264	        Ok(Ring {
265	            header,
266	            slots,
267	            slot_size,
268	            capacity,
269	            mask: capacity - 1,
270	            _region: PhantomData,
271	        })
272	    }
273	
274	    /// Split into the producer and consumer endpoint handles.
275	    ///
276	    /// - Consuming `self` makes each handle exist at most once
277	    ///   per ring per process; cross-process, one producing and
278	    ///   one consuming process is the SPSC contract.
279	    pub fn split(self) -> (Producer<'a>, Consumer<'a>) {
280	        (
281	            Producer::new(
282	                self.header,
283	                self.slots,
284	                self.slot_size,
285	                self.capacity,
286	                self.mask,
287	            ),
288	            Consumer::new(self.header, self.slots, self.slot_size, self.mask),
289	        )
290	    }
291	}
292	
293	/// Validate a region base pointer and cast it to the `Header`
294	/// it must start with; shared by [`Ring::init`] / [`Ring::attach`].
295	///
296	/// - Checks alignment and room for the `Header` itself. The
297	///   full-geometry length check stays with the caller: init
298	///   knows the geometry from its parameters, attach only after
299	///   reading it from the returned header.
300	/// - Returns a raw pointer — no deref here. Each caller
301	///   discharges its own safety obligation (init: exclusive
302	///   borrow; attach: the caller's shared-mapping contract).
303	fn header_ptr(base: *mut u8, len: usize) -> Result<*const Header, Error> {
304	    if !(base as usize).is_multiple_of(CACHE_LINE_SIZE) {
305	        return Err(Error::Misaligned);
306	    }
307	    if len < size_of::<Header>() {
308	        return Err(Error::TooSmall);
309	    }
310	    Ok(base as *const Header)
311	}
312	
313	/// Bytes needed for a region with the given geometry.
314	///
315	/// - Computed in u64: the usize product can wrap on 32-bit
316	///   targets (e.g. N = 2^26, M = 2^6), which would validate a
317	///   tiny region and let safe code write out of bounds.
318	fn region_size(slot_size: u32, capacity: u32) -> u64 {
319	    size_of::<Header>() as u64 + slot_size as u64 * capacity as u64
320	}
321	
322	/// Shared geometry checks for [`Ring::init`] / [`Ring::attach`].
323	fn validate_geometry(slot_size: u32, capacity: u32) -> Result<(), Error> {
324	    if slot_size == 0 || !(slot_size as usize).is_multiple_of(CACHE_LINE_SIZE) {
325	        return Err(Error::BadSlotSize);
326	    }
327	    // The `> 1 << 31` arm is unreachable (u32 powers of two are
328	    // <= 2^31); it stays to document the M bound the occupancy
329	    // math relies on.
330	    if capacity == 0 || !capacity.is_power_of_two() || capacity > 1 << 31 {
331	        return Err(Error::BadCapacity);
332	    }
333	    Ok(())
334	}
335	
336	/// Check `T` fits a slot; called once per `reserve_slot_with`
337	/// (both endpoints).
338	///
339	/// - Panics on a type-geometry mismatch — that is a programming
340	///   error, not a runtime condition.
341	fn check_type<T>(slot_size: u32) {
342	    assert!(size_of::<T>() <= slot_size as usize, "T larger than slot");
343	    assert!(
344	        core::mem::align_of::<T>() <= CACHE_LINE_SIZE,
345	        "T alignment exceeds slot alignment"
346	    );
347	}
348	
349	/// Non-panicking form of [`check_type`], for descriptor
350	/// resolve — there the pool compared against is selected by
351	/// untrusted input, which must not be able to select a panic.
352	fn type_fits<T>(slot_size: u32) -> bool {
353	    size_of::<T>() <= slot_size as usize && core::mem::align_of::<T>() <= CACHE_LINE_SIZE
354	}
355	
356	/// Pointer to the slot for free-running index `idx`.
357	///
358	/// - Returned range is `slot_size` bytes, cache-line aligned
359	///   (base is, and slot_size is a line multiple).
360	fn slot_ptr(slots: *mut u8, idx: u32, mask: u32, slot_size: u32) -> *mut u8 {
361	    let pos = (idx & mask) as usize;
362	    // SAFETY: pos < capacity, so the offset is inside the slot
363	    // array validated at init/attach.
364	    unsafe { slots.add(pos * slot_size as usize) }
365	}
