539	    // no Drop impl by design (abandon = do nothing).
540	    #[allow(clippy::drop_non_drop)]
541	    fn abandoned_guards_publish_nothing() {
542	        let mut r = Region::new();
543	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
544	
545	        // Reserve then drop: nothing published.
546	        let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
547	        slot.seq = 99;
548	        drop(slot);
549	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
550	
551	        // Commit one, reserve then drop: still unread, the
552	        // next reservation returns it again.
553	        let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
554	        slot.seq = 1;
555	        slot.commit();
556	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
557	        assert_eq!(msg.seq, 1);
558	        drop(msg);
559	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
560	        assert_eq!(msg.seq, 1);
561	        msg.release();
562	    }
