564	    #[test]
565	    fn threaded_spsc() {
566	        // Reduced under Miri: interpreted spin loops are slow,
567	        // and its scheduler explores interleavings at any count.
568	        const COUNT: u64 = if cfg!(miri) { 200 } else { 100_000 };
569	        let mut r = Region::new();
570	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
571	
572	        std::thread::scope(|s| {
573	            s.spawn(move || {
574	                for i in 0..COUNT {
575	                    loop {
576	                        match prod.reserve_slot_with::<Msg>(|_| false) {
577	                            Ok(mut slot) => {
578	                                slot.seq = i;
579	                                slot.val = i * 3;
580	                                slot.commit();
581	                                break;
582	                            }
583	                            Err(Full) => std::hint::spin_loop(),
584	                        }
585	                    }
586	                }
587	            });
588	            s.spawn(move || {
589	                for i in 0..COUNT {
590	                    loop {
591	                        match cons.reserve_slot_with::<Msg>(|_| false) {
592	                            Ok(msg) => {
593	                                assert_eq!(msg.seq, i);
594	                                assert_eq!(msg.val, i * 3);
595	                                msg.release();
596	                                break;
597	                            }
598	                            Err(Empty) => std::hint::spin_loop(),
599	                        }
600	                    }
601	                }
602	            });
603	        });
604	    }
605	
606	    #[test]
607	    fn reserve_slot_with_policy_counts_and_gives_up() {
608	        let mut r = Region::new();
609	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
610	
611	        // Empty ring: the consumer's policy sees 0-based
612	        // attempts and its `false` becomes Err(Empty).
613	        let mut seen = Vec::new();
614	        let err = cons
615	            .reserve_slot_with::<Msg>(|attempt| {
616	                seen.push(attempt);
617	                attempt < 2
618	            })
619	            .err()
620	            .unwrap();
621	        assert_eq!(err, Empty);
622	        assert_eq!(seen, [0, 1, 2]);
623	
624	        // Fill the ring: the producer's policy gives up with
625	        // Err(Full).
626	        for i in 0..4 {
627	            let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
628	            slot.seq = i;
629	            slot.commit();
630	        }
631	        let err = prod
632	            .reserve_slot_with::<Msg>(|attempt| attempt < 2)
633	            .err()
634	            .unwrap();
635	        assert_eq!(err, Full);
636	
637	        // With room / messages available the policy is never
638	        // consulted.
639	        let msg = cons
640	            .reserve_slot_with::<Msg>(|_| panic!("policy consulted with a message available"))
641	            .unwrap();
642	        assert_eq!(msg.seq, 0);
643	        msg.release();
644	        let mut slot = prod
645	            .reserve_slot_with::<Msg>(|_| panic!("policy consulted with room available"))
646	            .unwrap();
647	        slot.seq = 4;
648	        slot.commit();
649	    }
