    const REGION_BYTES: usize = size_of::<Header>() + (4 * CACHE_LINE_SIZE);

    /// Cache-line-aligned backing store for the tests' rings.
    #[repr(C, align(64))]
    struct Region([u8; REGION_BYTES]);

